{"output": "#!/usr/bin/env python3
"""
Simple HTML Dashboard for Hermes ↔ OpenClaw Status
Serves on port 9119
"""
from http.server import HTTPServer, BaseHTTPRequestHandler
import json, subprocess, time
from datetime import datetime

PORT = 9119

def get_status():
    try:
        # Services
        services = {}
        for svc in ['hermes.service', 'hermes-gateway-discord.service', 
                    'hermes-interop.service', 'openclaw-gateway.service']:
            r = subprocess.run(['systemctl', '--user', 'is-active', svc],
                             capture_output=True, text=True, timeout=3)
            services[svc] = '🟢 active' if r.stdout.strip() == 'active' else '🔴 inactive'

        # Interop
        try:
            import urllib.request
            with urllib.request.urlopen('http://127.0.0.1:18900/status', timeout=2) as resp:
                interop = json.loads(resp.read())
        except:
            interop = None

        # Uptime
        r = subprocess.run(['uptime'], capture_output=True, text=True, timeout=2)
        uptime = r.stdout.strip()

        return {'services': services, 'interop': interop, 'uptime': uptime, 'time': datetime.now().isoformat()}
    except Exception as e:
        return {'error': str(e)}

def get_html(status):
    agents_html = ""
    if status.get('interop'):
        for agent, info in status['interop'].get('agents', {}).items():
            emoji = '🟢' if info.get('status') == 'online' else '🔴'
            q = status['interop']['queues'].get(agent, 0)
            agents_html += f"<li><span class='agent'>{emoji} {agent}</span>: {info.get('status', 'unknown')} (queue: {q})</li>"
    else:
        agents_html = "<li>🔴 Bridge unreachable</li>"

    services_html = ""
    for svc, state in status.get('services', {}).items():
        emoji = '🟢' if 'active' in state else '🔴'
        name = svc.replace('.service', '').replace('hermes-', 'Hermes ').replace('openclaw-', 'OpenClaw ')
        services_html += f"<li>{emoji} {name}: {state}</li>"

    html = f"""<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Hermes ↔ OpenClaw Dashboard</title>
<style>
  * {{ margin: 0; padding: 0; box-sizing: border-box; }}
  body {{ font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; 
          background: #0d1117; color: #e6edf3; min-height: 100vh; padding: 20px; }}
  .container {{ max-width: 900px; margin: 0 auto; }}
  h1 {{ color: #58a6ff; margin-bottom: 5px; font-size: 1.5rem; }}
  .subtitle {{ color: #8b949e; font-size: 0.85rem; margin-bottom: 25px; }}
  .card {{ background: #161b22; border: 1px solid #30363d; border-radius: 8px; 
          padding: 16px; margin-bottom: 16px; }}
  .card h2 {{ color: #58a6ff; font-size: 0.9rem; text-transform: uppercase; 
               letter-spacing: 0.5px; margin-bottom: 12px; border-bottom: 1px solid #30363d; 
               padding-bottom: 8px; }}
  ul {{ list-style: none; }}
  li {{ padding: 6px 0; font-size: 0.95rem; border-bottom: 1px solid #21262d; }}
  li:last-child {{ border-bottom: none; }}
  .agent {{ font-weight: 600; color: #e6edf3; }}
  .uptime {{ font-size: 0.85rem; color: #8b949e; }}
  .badge {{ display: inline-block; padding: 2px 8px; border-radius: 12px; 
            font-size: 0.75rem; margin-left: 8px; }}
  .badge-ok {{ background: #238636; color: #fff; }}
  .badge-warn {{ background: #9e6a03; color: #fff; }}
  .actions a {{ color: #58a6ff; text-decoration: none; margin-right: 16px; font-size: 0.9rem; }}
  .actions a:hover {{ text-decoration: underline; }}
  .footer {{ text-align: center; color: #484f58; font-size: 0.75rem; margin-top: 30px; }}
  .refresh {{ float: right; font-size: 0.8rem; color: #58a6ff; text-decoration: none; }}
  .refresh:hover {{ text-decoration: underline; }}
</style>
</head>
<body>
<div class="container">
  <h1>⚡ Hermes ↔ OpenClaw Dashboard</h1>
  <p class="subtitle">System status at {datetime.now().strftime('%H:%M:%S')}</p>

  <div class="card">
    <h2>🤖 Agents</h2>
    <ul>{agents_html}</ul>
  </div>

  <div class="card">
    <h2>⚙️ Services <a href='/' class='refresh'>🔄</a></h2>
    <ul>{services_html}</ul>
  </div>

  <div class="card">
    <h2>💬 Quick Actions</h2>
    <div class="actions">
      <a href='/restart/hermes'>Restart Hermes</a>
      <a href='/restart/discord'>Restart Discord Gateway</a>
      <a href='/broadcast'>Send Broadcast</a>
    </div>
  </div>

  <div class="card">
    <h2>📊 System</h2>
    <p class="uptime">{status.get('uptime', 'N/A')}</p>
  </div>

  <p class="footer">
    Auto-refreshes every 30s · Hermes Surface Pro 3
  </p>
</div>
<script>
  setTimeout(() => location.reload(), 30000);
</script>
</body>
</html>"""
    return html

class Handler(BaseHTTPRequestHandler):
    def do_GET(self):
        if self.path == '/' or self.path == '/index.html':
            status = get_status()
            html = get_html(status)
            self.send_response(200)
            self.end_headers()
            self.wfile.write(html.encode())

        elif self.path.startswith('/restart/'):
            service = self.path.split('/')[-1]
            service_map = {
                'hermes': 'hermes.service',
                'discord': 'hermes-gateway-discord.service',
                'interop': 'hermes-interop.service',
            }
            svc = service_map.get(service, '')
            if svc:
                subprocess.run(['systemctl', '--user', 'restart', svc], 
                             capture_output=True, timeout=10)
                self.send_response(302)
                self.send_header('Location', '/')
                self.end_headers()
            else:
                self.send_response(404)
                self.end_headers()
                self.wfile.write(b'Unknown service')
            return

        elif self.path == '/broadcast':
            html = """<!DOCTYPE html><html><body>
            <form method="POST" action="/broadcast" style="padding:20px">
              <h2>Send Broadcast</h2>
              <input type="hidden" name="from" value="openclaw">
              <textarea name="text" placeholder="Message..." style="width:100%;height:100px"></textarea>
              <br><br>
              <button type="submit">Send</button>
            </form>
            <a href="/">Back</a>
            </body></html>"""
            self.send_response(200)
            self.end_headers()
            self.wfile.write(html.encode())
            return

        else:
            self.send_response(404)
            self.end_headers()
            self.wfile.write(b'Not found')

    def do_POST(self):
        if self.path == '/broadcast':
            import urllib.parse, urllib.request, cgi
            cl = int(self.headers.get('Content-Length', 0))
            body = self.rfile.read(cl).decode()
            params = dict(urllib.parse.parse_qsl(body))
            sender = params.get('from', 'openclaw')
            text = params.get('text', '')

            if text:
                try:
                    data = json.dumps({'text': text}).encode()
                    req = urllib.request.Request(
                        'http://127.0.0.1:18900/broadcast?from=' + sender,
                        data=data,
                        headers={'Content-Type': 'application/json'}
                    )
                    urllib.request.urlopen(req, timeout=5)
                except:
                    pass

            self.send_response(302)
            self.send_header('Location', '/')
            self.end_headers()
            return

        self.send_response(404)
        self.end_headers()

    def log_message(self, *args):
        pass

def run_server():
    server = HTTPServer(('0.0.0.0', PORT), Handler)
    print(f"[dashboard] Dashboard ready on http://localhost:{PORT}", flush=True)
    server.serve_forever()

run_server()", "exit_code": 0, "error": null}

